from enum import Enum
from typing import List

class ReportType(Enum):
    MONTHLY = 1
    QUARTERLY = 2
    YEARLY = 3

@dataclass
class Transaction:
    date: datetime.date
    amount: float
    description: str

class AccountingReport:
    def __init__(self, transactions: List[Transaction]):
        self.transactions = transactions

    def generate_report(self, report_type: ReportType):
        if report_type == ReportType.MONTHLY:
            return self.generate_monthly_report()
        elif report_type == ReportType.QUARTERLY:
            return self.generate_quarterly_report()
        elif report_type == ReportType.YEARLY:
            return self.generate_yearly_report()

    def generate_monthly_report(self):
        report = {}
        for transaction in self.transactions:
            month = transaction.date.strftime("%Y-%m")
            if month not in report:
                report[month] = []
            report[month].append(transaction)
        return report

    def generate_quarterly_report(self):
        report = {}
        for transaction in self.transactions:
            quarter = f"{transaction.date.year}-Q{((transaction.date.month - 1) // 3) + 1}"
            if quarter not in report:
                report[quarter] = []
            report[quarter].append(transaction)
        return report

    def generate_yearly_report(self):
        report = {}
        for transaction in self.transactions:
            year = transaction.date.year
            if year not in report:
                report[year] = []
            report[year].append(transaction)
        return report

    def print_report(self, report):
        for period, transactions in report.items():
            print(f"Period: {period}")
            total = sum(transaction.amount for transaction in transactions)
            print(f"Total: {total}")
            for transaction in transactions:
                print(f"Date: {transaction.date}, Amount: {transaction.amount}, Description: {transaction.description}")
            print()

