import datetime
import pandas as pd

class AccountingReport:
    def __init__(self, data):
        self.data = data

    def generate_report(self, timeframe):
        if timeframe == 'month':
            return self.generate_monthly_report()
        elif timeframe == 'quarter':
            return self.generate_quarterly_report()
        elif timeframe == 'year':
            return self.generate_yearly_report()
        else:
            raise ValueError('Invalid timeframe')

    def generate_monthly_report(self):
        report = []
        for month in self.data['date'].dt.to_period('M').unique():
            month_data = self.data[self.data['date'].dt.to_period('M') == month]
            total_revenue = month_data['revenue'].sum()
            total_expenses = month_data['expenses'].sum()
            net_income = total_revenue - total_expenses
            report.append({
                'month': month,
                'total_revenue': total_revenue,
                'total_expenses': total_expenses,
                'net_income': net_income
            })
        return pd.DataFrame(report)

    def generate_quarterly_report(self):
        report = []
        for quarter in self.data['date'].dt.to_period('Q').unique():
            quarter_data = self.data[self.data['date'].dt.to_period('Q') == quarter]
            total_revenue = quarter_data['revenue'].sum()
            total_expenses = quarter_data['expenses'].sum()
            net_income = total_revenue - total_expenses
            report.append({
                'quarter': quarter,
                'total_revenue': total_revenue,
                'total_expenses': total_expenses,
                'net_income': net_income
            })
        return pd.DataFrame(report)

    def generate_yearly_report(self):
        report = []
        for year in self.data['date'].dt.to_period('Y').unique():
            year_data = self.data[self.data['date'].dt.to_period('Y') == year]
            total_revenue = year_data['revenue'].sum()
            total_expenses = year_data['expenses'].sum()
            net_income = total_revenue - total_expenses
            report.append({
                'year': year,
                'total_revenue': total_revenue,
                'total_expenses': total_expenses,
                'net_income': net_income
            })
        return pd.DataFrame(report)

def load_data(file_path):
    return pd.read_csv(file_path, parse_dates=['date'])

def save_report(report, file_path):
    report.to_csv(file_path, index=False)

def main():
    data = load_data('accounting_data.csv')
    report = AccountingReport(data)
    monthly_report = report.generate_report('month')
    quarterly_report = report.generate_report('quarter')
    yearly_report = report.generate_report('year')
    save_report(monthly_report, 'monthly_report.csv')
    save_report(quarterly_report, 'quarterly_report.csv')
    save_report(yearly_report, 'yearly_report.csv')

if __name__ == '__main__':
    main()

import datetime
import pandas as pd

class AccountingReport:
    def __init__(self, data):
        self.data = data

    def generate_report(self, timeframe):
        if timeframe == 'month':
            return self.generate_monthly_report()
        elif timeframe == 'quarter':
            return self.generate_quarterly_report()
        elif timeframe == 'year':
            return self.generate_yearly_report()
        else:
            raise ValueError('Invalid timeframe')

    def generate_monthly_report(self):
        report = {}
        for month in range(1, 13):
            start_date = datetime.date(datetime.date.today().year, month, 1)
            if month == 12:
                end_date = datetime.date(datetime.date.today().year, month, 31)
            else:
                end_date = datetime.date(datetime.date.today().year, month + 1, 1) - datetime.timedelta(days=1)
            report[datetime.date(1900, month, 1).strftime('%B')] = self.calculate_report_data(start_date, end_date)
        return report

    def generate_quarterly_report(self):
        report = {}
        for quarter in range(1, 5):
            if quarter == 1:
                start_date = datetime.date(datetime.date.today().year, 1, 1)
                end_date = datetime.date(datetime.date.today().year, 3, 31)
            elif quarter == 2:
                start_date = datetime.date(datetime.date.today().year, 4, 1)
                end_date = datetime.date(datetime.date.today().year, 6, 30)
            elif quarter == 3:
                start_date = datetime.date(datetime.date.today().year, 7, 1)
                end_date = datetime.date(datetime.date.today().year, 9, 30)
            else:
                start_date = datetime.date(datetime.date.today().year, 10, 1)
                end_date = datetime.date(datetime.date.today().year, 12, 31)
            report[f'Q{quarter}'] = self.calculate_report_data(start_date, end_date)
        return report

    def generate_yearly_report(self):
        report = {}
        start_date = datetime.date(datetime.date.today().year, 1, 1)
        end_date = datetime.date(datetime.date.today().year, 12, 31)
        report['Year'] = self.calculate_report_data(start_date, end_date)
        return report

    def calculate_report_data(self, start_date, end_date):
        report_data = {
            'revenue': 0,
            'expenses': 0,
            'profit': 0
        }
        for transaction in self.data:
            if start_date <= transaction['date'] <= end_date:
                if transaction['type'] == 'income':
                    report_data['revenue'] += transaction['amount']
                elif transaction['type'] == 'expense':
                    report_data['expenses'] += transaction['amount']
        report_data['profit'] = report_data['revenue'] - report_data['expenses']
        return report_data

def main():
    data = [
        {'date': datetime.date(2022, 1, 1), 'type': 'income', 'amount': 1000},
        {'date': datetime.date(2022, 1, 15), 'type': 'expense', 'amount': 500},
        {'date': datetime.date(2022, 2, 1), 'type': 'income', 'amount': 1200},
